package serviceimpl

import (
	"context"
	"fmt"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	claudeharness "github.com/easel/fizeau/internal/harnesses/claude"
	codexharness "github.com/easel/fizeau/internal/harnesses/codex"
	geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
	opencodeharness "github.com/easel/fizeau/internal/harnesses/opencode"
	piharness "github.com/easel/fizeau/internal/harnesses/pi"
)

// ExecuteDispatchRequest carries API-neutral data needed to choose the
// concrete execute runner.
type ExecuteDispatchRequest struct {
	Decision ExecuteRunnerDecision
	Started  time.Time
}

// ExecuteDispatchCallbacks connect the internal dispatcher to root-owned
// public event/session adapters.
type ExecuteDispatchCallbacks struct {
	RunNative      func(context.Context)
	RunSubprocess  func(context.Context, harnesses.Harness)
	RunVirtual     func(context.Context)
	RunScript      func(context.Context)
	IsHTTPProvider func(harness string) bool
	Finalize       func(harnesses.FinalData)
}

// DispatchExecuteRun selects the concrete runner for an Execute request.
func DispatchExecuteRun(ctx context.Context, req ExecuteDispatchRequest, cb ExecuteDispatchCallbacks) {
	switch req.Decision.Harness {
	case "fiz", "":
		if cb.RunNative != nil {
			cb.RunNative(ctx)
		}
	case "claude":
		runSubprocess(ctx, cb, &claudeharness.Runner{})
	case "codex":
		runSubprocess(ctx, cb, &codexharness.Runner{})
	case "gemini":
		runSubprocess(ctx, cb, &geminiharness.Runner{})
	case "opencode":
		runSubprocess(ctx, cb, &opencodeharness.Runner{})
	case "pi":
		runSubprocess(ctx, cb, &piharness.Runner{})
	case "virtual":
		if cb.RunVirtual != nil {
			cb.RunVirtual(ctx)
		}
	case "script":
		if cb.RunScript != nil {
			cb.RunScript(ctx)
		}
	default:
		if cb.IsHTTPProvider != nil && cb.IsHTTPProvider(req.Decision.Harness) {
			if cb.RunNative != nil {
				cb.RunNative(ctx)
			}
			return
		}
		finalizeDispatch(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      fmt.Sprintf("harness %q dispatch not yet wired in service.Execute", req.Decision.Harness),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        req.Decision.Harness,
				Provider:       req.Decision.Provider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          req.Decision.Model,
			},
		})
	}
}

func runSubprocess(ctx context.Context, cb ExecuteDispatchCallbacks, runner harnesses.Harness) {
	if cb.RunSubprocess != nil {
		cb.RunSubprocess(ctx, runner)
	}
}

func finalizeDispatch(cb ExecuteDispatchCallbacks, final harnesses.FinalData) {
	if cb.Finalize != nil {
		cb.Finalize(final)
	}
}

package serviceimpl

import (
	"fmt"
	"path/filepath"
)

// SessionLogDir resolves the public service session-log directory from the
// per-service override and the loaded config value.
func SessionLogDir(overrideDir, configDir string) string {
	if overrideDir != "" {
		return overrideDir
	}
	return configDir
}

// SessionLogPath resolves the JSONL path for a public service session.
func SessionLogPath(dir, sessionID string) (string, error) {
	if sessionID == "" {
		return "", fmt.Errorf("session id is required")
	}
	if dir == "" {
		return "", fmt.Errorf("session log directory is not configured")
	}
	return filepath.Join(dir, sessionID+".jsonl"), nil
}

package serviceimpl

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"sort"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/session"
)

// SessionLogEntry is an API-neutral projection of one service session log.
type SessionLogEntry struct {
	SessionID string
	ModTime   time.Time
	Size      int64
}

// UsageReport aggregates session usage from the service-owned log directory.
func UsageReport(ctx context.Context, logDir string, opts session.UsageOptions) (*session.UsageReport, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	return session.AggregateUsage(logDir, opts)
}

// ListSessionLogs returns JSONL session logs sorted by session ID.
func ListSessionLogs(ctx context.Context, logDir string) ([]SessionLogEntry, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if logDir == "" {
		return nil, nil
	}
	entries, err := os.ReadDir(logDir)
	if err != nil {
		return nil, err
	}
	out := make([]SessionLogEntry, 0, len(entries))
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".jsonl") {
			continue
		}
		id := strings.TrimSuffix(e.Name(), ".jsonl")
		entry := SessionLogEntry{SessionID: id}
		if info, err := e.Info(); err == nil && info != nil {
			entry.ModTime = info.ModTime()
			entry.Size = info.Size()
		}
		out = append(out, entry)
	}
	sort.Slice(out, func(i, j int) bool { return out[i].SessionID < out[j].SessionID })
	return out, nil
}

// WriteSessionLog writes the raw session events as indented JSON objects.
func WriteSessionLog(ctx context.Context, path string, w io.Writer) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	events, err := session.ReadEvents(path)
	if err != nil {
		return err
	}
	for _, e := range events {
		data, err := json.MarshalIndent(e, "", "  ")
		if err != nil {
			return err
		}
		if _, err := fmt.Fprintln(w, string(data)); err != nil {
			return err
		}
	}
	return nil
}

// ReplaySession renders a human-readable transcript for one session log path.
func ReplaySession(ctx context.Context, path string, w io.Writer) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	return session.Replay(path, w)
}

