)

const (
	defaultStallReadOnlyIterations = 25
	defaultMaxIterations           = 200
)

var nativeReadOnlyTools = map[string]bool{
	"read":       true,
	"read_file":  true,
	"grep":       true,
	"ls":         true,
	"find":       true,
	"cat":        true,
	"head":       true,
	"tail":       true,
	"stat":       true,
	"web_fetch":  true,
	"web_search": true,
}

// NativeDecision is the API-neutral routing data needed by the native runner.
type NativeDecision struct {
	Harness        string
	Provider       string
	ServerInstance string
	Model          string
	Candidates     []NativeRouteCandidate
}

// NativeRouteCandidate is the API-neutral subset of root RouteCandidate used
// by the native failover provider.
type NativeRouteCandidate struct {
	Provider       string
	Endpoint       string
	ServerInstance string
	Model          string
	Eligible       bool
}

// NativeRequest is the API-neutral request data needed by the native runner.
type NativeRequest struct {
	Prompt                    string
	SystemPrompt              string
	Model                     string
	Provider                  string
	Harness                   string
	WorkDir                   string
	Temperature               *float32
	TopP                      *float64
	TopK                      *int
	MinP                      *float64
	RepetitionPenalty         *float64
	Seed                      *int64
	SamplingSource            string
	Reasoning                 agentcore.Reasoning
	NoStream                  bool
	Permissions               string
	Tools                     []agentcore.Tool
	ToolPreset                string
	PlanningMode              bool
	MaxIterations             int
	MaxTokens                 int
	ReasoningByteLimit        int
	ProviderTimeout           time.Duration
	Timeout                   time.Duration
	CachePolicy               string
	StallMaxReadOnlyIteration *int
	Metadata                  map[string]string
	Decision                  NativeDecision
	Started                   time.Time
	SessionID                 string
	// CostCapUSD mirrors ServiceExecuteRequest.CostCapUSD. See
	// internal/core.Request.CostCapUSD for the enforcement contract.
	CostCapUSD float64
}

// NativeProviderRequest is the narrow provider-selection request that crosses
// from the internal runner back into root-owned provider configuration.
type NativeProviderRequest struct {
	Provider string
	Harness  string
	Model    string
}

// NativeProviderResolution is the API-neutral result of root-owned provider
// construction.
type NativeProviderResolution struct {
	Provider agentcore.Provider
	Name     string
	Model    string
}

// NativeCallbacks are root-owned service seams used by the internal runner
// without importing root public contract types.
type NativeCallbacks struct {
	ResolveProvider            func(NativeProviderRequest) NativeProviderResolution
	ProviderNotConfiguredError func(NativeProviderRequest, NativeDecision) string
	Compactor                  func(model string) agentcore.Compactor
	ObserveAgentEvent          func(agentcore.Event)
	EmitEvent                  func(harnesses.EventType, any)
	BeforeFinal                func(harnesses.FinalData)
	Finalize                   func(harnesses.FinalData)
	ToolWiringHook             func(harness string, toolNames []string)
	PromptAssertionHook        func(systemPrompt, prompt string, contextFiles []string)
	CompactionAssertionHook    func(messagesBefore, messagesAfter, tokensFreed int)
	ObserveTokenUsage          func(provider string, tokens int, at time.Time)
}

// RunNative drives the in-process agent loop without depending on root public
// service types.
func RunNative(ctx context.Context, req NativeRequest, cb NativeCallbacks) {
	provider := nativeExecutionProvider(req, cb.ResolveProvider)
	actualHarness := req.Decision.Harness
	if actualHarness == "" {
		actualHarness = "fiz"
	}
	resolvedProvider := resolveProvider(cb.ResolveProvider, nativeProviderRequest(req, req.Decision))
	actualProvider := resolvedProvider.Name
	if actualProvider == "" {
		actualProvider = req.Decision.Provider
	}
	actualModel := req.Decision.Model
	if actualModel == "" {
		actualModel = resolvedProvider.Model
	}
	if provider == nil {
		finalize(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      providerNotConfiguredError(cb.ProviderNotConfiguredError, req, req.Decision),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        actualHarness,
				Provider:       actualProvider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          actualModel,
			},
		})
		return
	}
	permission, permissionErr := nativePermissionMode(req.Permissions)
	if permissionErr != nil {
		finalize(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      permissionErr.Error(),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        actualHarness,
				Provider:       actualProvider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          actualModel,
			},
		})
		return
	}

	if req.ProviderTimeout > 0 {
		provider = wrapProviderRequestTimeout(provider, req.ProviderTimeout)
	}

	policyMax := defaultStallReadOnlyIterations
	if req.StallMaxReadOnlyIteration != nil {
		policyMax = *req.StallMaxReadOnlyIteration
	}
	maxIter := req.MaxIterations
	if maxIter <= 0 {
		maxIter = defaultMaxIterations
	}

	var (
		readOnlyStreak atomic.Int64
		stalled        atomic.Bool
		stallReason    atomic.Value
		stallCount     atomic.Int64
	)
	cancelCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	loopCB := func(ev agentcore.Event) {
		if cb.ObserveAgentEvent != nil {
			cb.ObserveAgentEvent(ev)
		}
		switch ev.Type {
		case agentcore.EventToolCall:
			var payload nativeToolCallPayload
			_ = json.Unmarshal(ev.Data, &payload)
			if !toolLikelyMakesProgress(payload.Tool, payload) {
				if v := readOnlyStreak.Add(1); policyMax > 0 && int(v) >= policyMax {
					if stalled.CompareAndSwap(false, true) {
						stallReason.Store("no_progress_tools_exceeded")
						stallCount.Store(v)
						cancel()
					}
				}
			} else {
				readOnlyStreak.Store(0)
			}
		case agentcore.EventCompactionEnd:
			if cb.CompactionAssertionHook != nil {
				var payload nativeCompactionPayload
				_ = json.Unmarshal(ev.Data, &payload)
				cb.CompactionAssertionHook(payload.MessagesBefore, payload.MessagesAfter, payload.TokensBefore-payload.TokensAfter)
			}
		}
	}

	tools := filterNativeToolsForPermission(req.Tools, permission)
	if cb.ToolWiringHook != nil {
		cb.ToolWiringHook(req.Decision.Harness, ToolNames(tools))
	}
	if cb.PromptAssertionHook != nil {
		cb.PromptAssertionHook(req.SystemPrompt, req.Prompt, nil)
	}

	var compactor agentcore.Compactor
	if cb.Compactor != nil {
		compactor = cb.Compactor(actualModel)
	}
	var temperature *float64
	if req.Temperature != nil {
		t := float64(*req.Temperature)
		temperature = &t
	}
	var seed int64
	if req.Seed != nil {
		seed = *req.Seed
	}
	loopReq := agentcore.Request{
		Prompt:             req.Prompt,
		SystemPrompt:       req.SystemPrompt,
		Provider:           provider,
		Tools:              tools,
		WorkDir:            req.WorkDir,
		Callback:           loopCB,
		Metadata:           req.Metadata,
		MaxIterations:      maxIter,
		ResolvedModel:      actualModel,
		SelectedProvider:   actualProvider,
		Temperature:        temperature,
		TopP:               req.TopP,
		TopK:               req.TopK,
		MinP:               req.MinP,
		RepetitionPenalty:  req.RepetitionPenalty,
		Seed:               seed,
		SamplingSource:     req.SamplingSource,
		Reasoning:          req.Reasoning,
		NoStream:           req.NoStream,

type nativeToolCallPayload struct {
	Tool       string          `json:"tool"`
	Input      json.RawMessage `json:"input"`
	Output     string          `json:"output"`
	DurationMS int64           `json:"duration_ms"`
	Error      string          `json:"error"`
}

type nativeCompactionPayload struct {
	MessagesBefore int    `json:"messages_before"`
	MessagesAfter  int    `json:"messages_after"`
	TokensBefore   int    `json:"tokens_before"`
	TokensAfter    int    `json:"tokens_after"`
	Summary        string `json:"summary"`
	Warning        string `json:"warning"`
}

func toolLikelyMakesProgress(toolName string, payload nativeToolCallPayload) bool {
	if strings.TrimSpace(payload.Error) != "" {
		return false
	}
	if nativeReadOnlyTools[toolName] {
		return false
	}
	if toolName == "bash" {
		var input any
		if len(payload.Input) > 0 {
			if err := json.Unmarshal(payload.Input, &input); err == nil {
				return bashCommandLikelyMutates(extractBashCommand(input))
			}
		}
		return false
	}
	return true
}

func shouldRetryNativeNoStream(requestedStream bool, result agentcore.Result, runErr error) bool {
	if requestedStream || runErr != nil {
		return false
	}
	if result.Status != agentcore.StatusSuccess {
		return false
	}
	if result.Output != "" || len(result.ToolCalls) > 0 {
		return false
	}
	return result.Tokens.Input == 0 && result.Tokens.Output == 0 && result.Tokens.Total == 0
}

func classifyDispatchFailure(errMsg string) string {
	msg := strings.ToLower(errMsg)
	switch {
	case strings.Contains(msg, "no provider configured"),
		strings.Contains(msg, "not available"),
		strings.Contains(msg, "exhausted"),
		strings.Contains(msg, "not configured"):
		return "availability"
	case strings.Contains(msg, "timeout"),
		strings.Contains(msg, "deadline"),
		strings.Contains(msg, "connection"),
		strings.Contains(msg, "refused"),
		strings.Contains(msg, "no such host"),
		strings.Contains(msg, "transport"):
		return "transport"
	case strings.Contains(msg, "http "),
		strings.Contains(msg, "status "),
		strings.Contains(msg, "bad request"),
		strings.Contains(msg, "unauthorized"),
		strings.Contains(msg, "not found"),
		strings.Contains(msg, "unsupported"):
		return "protocol"
	default:
		return "unknown"
	}
}

func extractBashCommand(raw any) string {
	input, ok := raw.(map[string]any)
	if !ok {
		return ""
	}
	command, _ := input["command"].(string)
	return strings.TrimSpace(command)
}

func bashCommandLikelyMutates(command string) bool {
	command = strings.TrimSpace(strings.ToLower(command))
	if command == "" {
		return false
	}
	readOnlyPrefixes := []string{
		"cat ", "head ", "tail ", "ls", "find ", "grep ", "rg ", "sed -n",
		"awk ", "pwd", "git status", "git diff", "git log", "go test",
	}
	for _, prefix := range readOnlyPrefixes {
		if strings.HasPrefix(command, prefix) {
			return false
		}
	}
	mutatingFragments := []string{
		" mv ", " cp ", " rm ", "mkdir", "touch ", "chmod ", "chown ",
		"git add", "git commit", "git merge", "git pull", "git push",
		" gofmt", "go fmt", "npm install", "pip install", "cargo build",
		"cat >",
		"cat <<",
		"echo ",
		"mv ",
		"cp ",
		"rm ",
		"sed -i",
		"tee ",
		">",
		">>",
		"apply_patch",
		"patch ",
	}
	for _, fragment := range mutatingFragments {
		if strings.Contains(command, fragment) {
			return true
		}
	}
	return false
}

func finalUsageTotalTokens(u *harnesses.FinalUsage) int {
	if u == nil {
		return 0
	}
	if u.TotalTokens != nil && *u.TotalTokens > 0 {
		return *u.TotalTokens
	}
	var total int
	if u.InputTokens != nil {
		total += *u.InputTokens
	}
	if u.OutputTokens != nil {
		total += *u.OutputTokens
	}
	return total
}

func endpointProviderRef(providerName, endpointName string) string {
	if endpointName == "" {
		return providerName
	}
	return providerName + "@" + endpointName
}

func finalize(cb NativeCallbacks, final harnesses.FinalData) {
	if cb.Finalize != nil {
		cb.Finalize(final)
	}
}

var errProviderRequestTimeout = errors.New("provider request timeout")

func wrapProviderRequestTimeout(p agentcore.Provider, requestTimeout time.Duration) agentcore.Provider {
	if p == nil || requestTimeout <= 0 {
		return p
	}
	return &timeoutProviderInline{inner: p, requestTimeout: requestTimeout}
}

type timeoutProviderInline struct {
	inner          agentcore.Provider
	requestTimeout time.Duration
}

func (p *timeoutProviderInline) Chat(ctx context.Context, messages []agentcore.Message, tools []agentcore.ToolDef, opts agentcore.Options) (agentcore.Response, error) {
	if p.requestTimeout <= 0 {
		return p.inner.Chat(ctx, messages, tools, opts)
	}
	cctx, cancel := context.WithTimeout(ctx, p.requestTimeout)
	defer cancel()
	resp, err := p.inner.Chat(cctx, messages, tools, opts)
	if err != nil && ctx.Err() == nil && cctx.Err() == context.DeadlineExceeded {
		return resp, fmt.Errorf("%w: wall-clock %s", errProviderRequestTimeout, p.requestTimeout)
	}
	return resp, err
}

package serviceimpl

import (
	"context"
	"encoding/json"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/reasoning"
)

// SubprocessRequest is the API-neutral request data needed by subprocess
// harness runner implementations.
type SubprocessRequest struct {
	Prompt         string
	SystemPrompt   string
	WorkDir        string
	Permissions    string
	Temperature    *float32
	Seed           *int64
	Reasoning      reasoning.Reasoning
	Timeout        time.Duration
	IdleTimeout    time.Duration
	SessionLogDir  string
	Metadata       map[string]string
	Decision       ExecuteRunnerDecision
	Started        time.Time
	SessionLogPath string
}

// SubprocessCallbacks bridge service-owned event/progress/session-log behavior
// without importing root public service types.
type SubprocessCallbacks struct {
	BeforeExecute func()
	BeforeFinal   func(harnesses.FinalData)
	ObserveEvent  func(harnesses.Event) harnesses.Event
	EmitEvent     func(harnesses.Event) bool
	Finalize      func(harnesses.FinalData)
	WriteEnd      func(map[string]string, harnesses.FinalData)
}

// RunSubprocess executes a subprocess harness and forwards its event stream.
func RunSubprocess(ctx context.Context, req SubprocessRequest, runner harnesses.Harness, cb SubprocessCallbacks) {
	hReq := harnesses.ExecuteRequest{
		Prompt:        req.Prompt,
		SystemPrompt:  req.SystemPrompt,
		Provider:      req.Decision.Provider,
		Model:         req.Decision.Model,
		WorkDir:       req.WorkDir,
		Permissions:   req.Permissions,
		Temperature:   subprocessTemperature(req.Temperature),
		Seed:          subprocessSeed(req.Seed),
		Reasoning:     adapterReasoning(req.Reasoning),
		Timeout:       req.Timeout,
		IdleTimeout:   req.IdleTimeout,
		SessionLogDir: req.SessionLogDir,
		Metadata:      req.Metadata,
	}
	if cb.BeforeExecute != nil {
		cb.BeforeExecute()
	}
	in, err := runner.Execute(ctx, hReq)
	if err != nil {
		finalizeSubprocess(cb, harnesses.FinalData{
			Status:     "failed",
			Error:      err.Error(),
			DurationMS: time.Since(req.Started).Milliseconds(),
			RoutingActual: &harnesses.RoutingActual{
				Harness:        req.Decision.Harness,
				Provider:       req.Decision.Provider,
				ServerInstance: req.Decision.ServerInstance,
				Model:          req.Decision.Model,
			},
		})
		return
	}
	for ev := range in {
		if ev.Metadata == nil {
			ev.Metadata = req.Metadata
		}
		if ev.Type == harnesses.EventTypeFinal {
			var final harnesses.FinalData
			if err := json.Unmarshal(ev.Data, &final); err == nil && cb.BeforeFinal != nil {
				cb.BeforeFinal(final)
			}
			ev = stampSubprocessFinalRouting(ev, req.Decision)
			ev = stampSubprocessFinalSessionLog(ev, req.SessionLogPath)
			if err := json.Unmarshal(ev.Data, &final); err == nil && cb.WriteEnd != nil {
				cb.WriteEnd(req.Metadata, final)
			}
		}
		if cb.ObserveEvent != nil {
			ev = cb.ObserveEvent(ev)
		}
		if cb.EmitEvent != nil && !cb.EmitEvent(ev) {
			return
		}
	}
}

func subprocessTemperature(v *float32) float32 {
	if v == nil {
		return 0
	}
	return *v
}

func subprocessSeed(v *int64) int64 {
	if v == nil {
		return 0
	}
	return *v
}

func adapterReasoning(value reasoning.Reasoning) string {
	policy, err := reasoning.ParseString(string(value))
	if err != nil {
		return string(value)
	}
	switch policy.Kind {
	case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
		return ""
	case reasoning.KindTokens:
		if policy.Tokens == 0 {
			return ""
		}
		return string(policy.Value)
	case reasoning.KindNamed:
		return string(policy.Value)
	default:
		return string(value)
	}
}

func stampSubprocessFinalSessionLog(ev harnesses.Event, sessionLogPath string) harnesses.Event {
	if sessionLogPath == "" {
		return ev
	}
	var final harnesses.FinalData
	if err := json.Unmarshal(ev.Data, &final); err != nil {
		return ev
	}
	final.SessionLogPath = sessionLogPath
	raw, err := json.Marshal(final)
	if err != nil {
		return ev
	}
	ev.Data = raw
	return ev
}

func stampSubprocessFinalRouting(ev harnesses.Event, decision ExecuteRunnerDecision) harnesses.Event {
	var final harnesses.FinalData
	if err := json.Unmarshal(ev.Data, &final); err != nil {
		return ev
	}
	if final.RoutingActual == nil {
		final.RoutingActual = &harnesses.RoutingActual{
			Harness:        decision.Harness,
			Provider:       decision.Provider,
			ServerInstance: decision.ServerInstance,
			Model:          decision.Model,
		}
	}
	raw, err := json.Marshal(final)
	if err != nil {
		return ev
	}
	ev.Data = raw
	return ev
}

func finalizeSubprocess(cb SubprocessCallbacks, final harnesses.FinalData) {
	if cb.Finalize != nil {
		cb.Finalize(final)
	}
}

package serviceimpl

import (
	"context"
	"fmt"
	"strconv"
	"time"

	agentcore "github.com/easel/fizeau/internal/core"
	"github.com/easel/fizeau/internal/harnesses"
	virtualprovider "github.com/easel/fizeau/internal/provider/virtual"
)

// ExecuteRunnerDecision is the API-neutral routing data needed by internal
// virtual/script runner implementations.
type ExecuteRunnerDecision struct {
	Harness        string
	Provider       string
	ServerInstance string
	Model          string
}

// ExecuteRunnerRequest is the API-neutral request data needed by internal
// virtual/script runner implementations.
type ExecuteRunnerRequest struct {
	Prompt   string
	Metadata map[string]string
	Decision ExecuteRunnerDecision
	Started  time.Time
}

// ExecuteRunnerResult is the normalized result produced by an internal runner.
type ExecuteRunnerResult struct {
	Final    harnesses.FinalData
	Text     string
	EmitText bool
}

// RunVirtual executes the service virtual harness mechanics without depending
// on root public service types.
func RunVirtual(ctx context.Context, req ExecuteRunnerRequest) ExecuteRunnerResult {
	meta := req.Metadata
	inlineText := meta["virtual.response"]
	cfg := virtualprovider.Config{
		DictDir: meta["virtual.dict_dir"],
	}
	if inlineText != "" {
		cfg.InlineResponses = []virtualprovider.InlineResponse{{
			PromptMatch: metaValue(meta, "virtual.prompt_match", req.Prompt),
			Response: agentcore.Response{
				Content: inlineText,
				Usage: agentcore.TokenUsage{
					Input:  metadataInt(meta, "virtual.input_tokens"),
					Output: metadataInt(meta, "virtual.output_tokens"),
					Total:  metadataInt(meta, "virtual.total_tokens"),
				},
				Model: metaValue(meta, "virtual.model", req.Decision.Model),
			},
			DelayMS: metadataInt(meta, "virtual.delay_ms"),
		}}
	}
	if cfg.DictDir == "" && len(cfg.InlineResponses) == 0 {
		return ExecuteRunnerResult{Final: failedFinal(req, "virtual harness requires metadata virtual.response or virtual.dict_dir")}
	}

	resp, err := virtualprovider.New(cfg).Chat(ctx, []agentcore.Message{{Role: agentcore.RoleUser, Content: req.Prompt}}, nil, agentcore.Options{})
	final := harnesses.FinalData{
		DurationMS: durationMS(req.Started),
		RoutingActual: &harnesses.RoutingActual{
			Harness:        req.Decision.Harness,
			Provider:       req.Decision.Provider,
			ServerInstance: req.Decision.ServerInstance,
			Model:          metaValue(meta, "virtual.model", req.Decision.Model),
		},
	}
	if err != nil {
		final.Status = "failed"
		final.Error = err.Error()
		return ExecuteRunnerResult{Final: final}
	}
	final.Status = "success"
	final.FinalText = resp.Content
	final.Usage = &harnesses.FinalUsage{
		InputTokens:  harnesses.IntPtr(resp.Usage.Input),
		OutputTokens: harnesses.IntPtr(resp.Usage.Output),
		TotalTokens:  harnesses.IntPtr(resp.Usage.Total),
		Source:       harnesses.UsageSourceFallback,
	}
	return ExecuteRunnerResult{
		Final:    final,
		Text:     resp.Content,
		EmitText: resp.Content != "",
	}
}

// RunScript executes the service script harness mechanics without depending
// on root public service types.
func RunScript(ctx context.Context, req ExecuteRunnerRequest) ExecuteRunnerResult {
	meta := req.Metadata
	delay := metadataInt(meta, "script.delay_ms")
	if delay > 0 {
		timer := time.NewTimer(time.Duration(delay) * time.Millisecond)
		select {
		case <-ctx.Done():
			timer.Stop()
			return ExecuteRunnerResult{Final: failedOrCancelledFinal(req, "cancelled", ctx.Err().Error())}
		case <-timer.C:
		}
	}

	text, ok := meta["script.stdout"]
	if !ok {
		return ExecuteRunnerResult{Final: failedFinal(req, "script harness requires metadata script.stdout")}
	}
	exitCode := metadataInt(meta, "script.exit_code")
	final := harnesses.FinalData{
		Status:     "success",
		ExitCode:   exitCode,
		FinalText:  text,
		DurationMS: durationMS(req.Started),
		RoutingActual: &harnesses.RoutingActual{
			Harness:        req.Decision.Harness,
			Provider:       req.Decision.Provider,
			ServerInstance: req.Decision.ServerInstance,
			Model:          req.Decision.Model,
		},
	}
	if exitCode != 0 {
		final.Status = "failed"
		final.Error = metaValue(meta, "script.stderr", fmt.Sprintf("script exited with status %d", exitCode))
	}
	return ExecuteRunnerResult{
		Final:    final,
		Text:     text,
		EmitText: text != "",
	}
}

func failedFinal(req ExecuteRunnerRequest, msg string) harnesses.FinalData {
	return failedOrCancelledFinal(req, "failed", msg)
}

func failedOrCancelledFinal(req ExecuteRunnerRequest, status, msg string) harnesses.FinalData {
	return harnesses.FinalData{
		Status:     status,
		Error:      msg,
		DurationMS: durationMS(req.Started),
		RoutingActual: &harnesses.RoutingActual{
			Harness:        req.Decision.Harness,
			Provider:       req.Decision.Provider,
			ServerInstance: req.Decision.ServerInstance,
			Model:          req.Decision.Model,
		},
	}
}

func durationMS(started time.Time) int64 {
	if started.IsZero() {
		return 0
	}
	return time.Since(started).Milliseconds()
}

func metaValue(meta map[string]string, key, fallback string) string {
	if meta == nil {
		return fallback
	}
	if v := meta[key]; v != "" {
		return v
	}
	return fallback
}

func metadataInt(meta map[string]string, key string) int {
	if meta == nil {
		return 0
	}
	n, _ := strconv.Atoi(meta[key])
	return n
}

package serviceimpl

import "time"

// Clock is the API-neutral time seam used by service implementation state.
// It deliberately has no dependency on root package contract types so the
// root facade can import this package without creating a cycle.
type Clock func() time.Time

// SystemClock returns the current UTC wall-clock time.
func SystemClock() time.Time {
	return time.Now().UTC()
}

// RuntimeDeps groups constructor dependencies that are safe to pass from the
// root facade into internal implementation packages.
type RuntimeDeps struct {
	Now Clock
}

// Runtime is implementation-local service state that can be constructed from
// the root facade without depending on root public contract types.
type Runtime struct {
	deps RuntimeDeps
}

// NewRuntime constructs implementation state with defaulted dependencies.
func NewRuntime(deps RuntimeDeps) Runtime {
	return Runtime{deps: RuntimeDeps{Now: deps.Clock()}}
}

// Clock returns the configured clock or the system clock when no test seam is
// supplied.
func (d RuntimeDeps) Clock() Clock {
	if d.Now != nil {
		return d.Now
	}
	return SystemClock
}

// Now returns the runtime clock value normalized to UTC.
func (r Runtime) Now() time.Time {
	return r.deps.Clock()().UTC()
}

