package transcript

import (
	"fmt"
	"strings"
	"time"
	"unicode/utf8"
)

const (
	DefaultLineLimit         = 80
	ExceptionalToolLineLimit = 120
	compactElapsedWidth      = 7
	compactTurnWidth         = 2
)

type ProgressType string

const (
	ProgressTypeRoute        ProgressType = "route"
	ProgressTypeThinking     ProgressType = "thinking"
	ProgressTypeTool         ProgressType = "tool"
	ProgressTypeResponse     ProgressType = "response"
	ProgressTypeContext      ProgressType = "context"
	ProgressTypeCompaction   ProgressType = "compaction"
	ProgressTypeToolStart    ProgressType = "tool.start"
	ProgressTypeToolComplete ProgressType = "tool.complete"
	ProgressTypeLLMRequest   ProgressType = "llm.request"
	ProgressTypeLLMResponse  ProgressType = "llm.response"
)

type Callback func(Event)

type Event struct {
	Type      ProgressType `json:"type"`
	Source    string       `json:"source,omitempty"`
	TaskID    string       `json:"task_id,omitempty"`
	TurnIndex int          `json:"turn_index,omitempty"`
	Phase     string       `json:"phase,omitempty"`
	Status    string       `json:"status,omitempty"`
	Message   string       `json:"message,omitempty"`
	Action    string       `json:"action,omitempty"`
	Target    string       `json:"target,omitempty"`
	Tool      Tool         `json:"tool,omitempty"`
	LLM       LLM          `json:"llm,omitempty"`
	Timing    Timing       `json:"timing,omitempty"`
	Usage     Usage        `json:"usage,omitempty"`
	Output    Output       `json:"output,omitempty"`
}

type Tool struct {
	Name     string         `json:"name,omitempty"`
	CallID   string         `json:"call_id,omitempty"`
	Input    map[string]any `json:"input,omitempty"`
	ExitCode *int           `json:"exit_code,omitempty"`
	Error    string         `json:"error,omitempty"`
}

type LLM struct {
	Provider string `json:"provider,omitempty"`
	Model    string `json:"model,omitempty"`
}

type Timing struct {
	DurationMS int64   `json:"duration_ms,omitempty"`
	TokPerSec  float64 `json:"tok_per_sec,omitempty"`
}

type Usage struct {
	InputTokens        int `json:"input_tokens,omitempty"`
	OutputTokens       int `json:"output_tokens,omitempty"`
	CachedInputTokens  int `json:"cached_input_tokens,omitempty"`
	RetriedInputTokens int `json:"retried_input_tokens,omitempty"`
	TotalTokens        int `json:"total_tokens,omitempty"`
}

type Output struct {
	Bytes   int    `json:"bytes,omitempty"`
	Lines   int    `json:"lines,omitempty"`
	Excerpt string `json:"excerpt,omitempty"`
}

type StatusLineInput struct {
	TaskID      string
	TurnIndex   int
	Message     string
	SinceLastMS int64
	Limit       int
}

func StatusLine(in StatusLineInput) string {
	limit := in.Limit
	if limit <= 0 {
		limit = DefaultLineLimit
	}
	msg := strings.TrimSpace(in.Message)
	prefix := CompactIdentity(in.TaskID, in.TurnIndex)
	age := CompactElapsed(in.SinceLastMS)
	switch {
	case prefix == "" && age == "":
		return BoundedText(msg, limit)
	case prefix == "":
		return BoundedText(strings.TrimSpace(age+" "+msg), limit)
	case msg == "" && age == "":
		return BoundedText(prefix, limit)
	case msg == "":
		return BoundedText(prefix+" "+age, limit)
	case age == "":
		return BoundedText(prefix+" "+msg, limit)
	default:
		return BoundedText(prefix+" "+age+" "+msg, limit)
	}
}

func CompactElapsed(ms int64) string {
	if ms <= 0 {
		return ""
	}
	seconds := int64((time.Duration(ms)*time.Millisecond + 500*time.Millisecond) / time.Second)
	if seconds <= 0 {
		seconds = 1
	}
	var raw string
	switch {
	case seconds < 60:
		raw = fmt.Sprintf("+%ds", seconds)
	case seconds < 3600:
		raw = fmt.Sprintf("+%dm%02ds", seconds/60, seconds%60)
	default:
		hours := seconds / 3600
		minutes := (seconds % 3600) / 60
		if hours < 10 {
			raw = fmt.Sprintf("+%dh%02dm", hours, minutes)
		} else {
			raw = fmt.Sprintf("+%dh", hours)
		}
	}
	return fmt.Sprintf("%*s", compactElapsedWidth, raw)
}

func CompactIdentity(taskID string, turnIndex int) string {
	taskID = CompactTaskID(taskID)
	switch {
	case taskID != "" && turnIndex > 0:
		return fmt.Sprintf("%s #%*d", taskID, compactTurnWidth, turnIndex)
	case taskID != "":
		return taskID
	case turnIndex > 0:
		return fmt.Sprintf("#%*d", compactTurnWidth, turnIndex)
	default:
		return ""
	}
}

func CompactTaskID(taskID string) string {
	taskID = strings.TrimSpace(taskID)
	if taskID == "" {
		return ""
	}
	return BoundedText(taskID, 24)
}

func TaskID(sessionID string, meta map[string]string) string {
	for _, key := range []string{"task_id", "bead_id", "correlation_id"} {
		if meta != nil && strings.TrimSpace(meta[key]) != "" {
			return strings.TrimSpace(meta[key])
		}
	}
	return sessionID
}

func BoundedText(s string, maxRunes int) string {
	s = strings.TrimSpace(s)
	if maxRunes <= 0 || s == "" {
		return ""
	}
	if utf8.RuneCountInString(s) <= maxRunes {
		return s
	}
	runes := []rune(s)
	if maxRunes <= 3 {
		return string(runes[:maxRunes])
	}
	return string(runes[:maxRunes-3]) + "..."
}

package transcript

import (
	"encoding/json"
	"fmt"
	"regexp"
	"sort"
	"strconv"
	"strings"
)

type ToolSummary struct {
	Action string
	Target string
}

type OutputSummary struct {
	Summary string
	Bytes   int
	Lines   int
	Excerpt string
}

func SummarizeToolCall(toolName string, input json.RawMessage) ToolSummary {
	toolName = strings.TrimSpace(toolName)
	payload := map[string]any{}
	if len(input) > 0 {
		_ = json.Unmarshal(input, &payload)
	}
	path := summaryString(payload, "path", "file")
	switch toolName {
	case "read":
		if path != "" {
			return ToolSummary{Action: "inspect " + lineRangeSummary(payload) + " in " + path, Target: path}
		}
		return ToolSummary{Action: "inspect file"}
	case "write":
		return ToolSummary{Action: "write file", Target: path}
	case "edit", "anchor_edit":
		return ToolSummary{Action: "edit file", Target: path}
	case "patch":
		action := "edit file"
		if op := summaryString(payload, "operation"); op != "" {
			action = op + " file"
		}
		return ToolSummary{Action: action, Target: path}
	case "grep":
		pattern := summaryString(payload, "pattern")
		target := firstNonEmpty(summaryString(payload, "dir"), summaryString(payload, "glob"))
		action := "search"
		if pattern != "" {
			action += " " + strconv.Quote(BoundedText(pattern, 32))
		}
		if target != "" {
			action += " in " + target
		}
		return ToolSummary{Action: action, Target: target}
	case "find":
		pattern := summaryString(payload, "pattern")
		target := summaryString(payload, "dir")
		action := "find files"
		if pattern != "" {
			action += " matching " + strconv.Quote(BoundedText(pattern, 32))
		}
		if target != "" {
			action += " in " + target
		}
		return ToolSummary{Action: action, Target: target}
	case "ls":
		target := summaryString(payload, "path")
		if target == "" {
			target = "."
		}
		return ToolSummary{Action: "list directory " + target, Target: target}
	case "bash":
		return SummarizeShellCommand(ExtractBashCommand(payload))
	default:
		if path != "" {
			return ToolSummary{Action: toolName, Target: path}
		}
		if toolName != "" {
			return ToolSummary{Action: toolName}
		}
		return ToolSummary{}
	}
}

func SummarizeShellCommand(command string) ToolSummary {
	command = NormalizeShellCommand(command)
	fields := strings.Fields(command)
	if len(fields) == 0 {
		return ToolSummary{}
	}
	switch fields[0] {
	case "sed":
		if len(fields) >= 4 && fields[1] == "-n" {
			target := fields[3]
			return ToolSummary{Action: "inspect " + shellLineRange(fields[2]) + " in " + target, Target: target}
		}
	case "cat", "head", "tail":
		if len(fields) >= 2 {
			target := fields[len(fields)-1]
			return ToolSummary{Action: "inspect " + target, Target: target}
		}
	case "rg", "grep":
		return summarizeSearchCommand(fields)
	case "go":
		if len(fields) >= 2 && fields[1] == "test" {
			target := strings.Join(fields[2:], " ")
			return ToolSummary{Action: strings.TrimSpace("test " + target), Target: target}
		}
	case "git":
		return summarizeGitCommand(fields)
	case "apply_patch":
		return ToolSummary{Action: "apply patch"}
	}
	return ToolSummary{Action: BoundedText(command, 96)}
}

func NormalizeShellCommand(command string) string {
	command = strings.TrimSpace(command)
	for _, prefix := range []string{"/bin/zsh -lc ", "zsh -lc ", "/bin/bash -lc ", "bash -lc ", "/bin/sh -lc ", "sh -lc "} {
		if !strings.HasPrefix(command, prefix) {
			continue
		}
		inner := strings.TrimSpace(strings.TrimPrefix(command, prefix))
		if unquoted, err := strconv.Unquote(inner); err == nil {
			command = unquoted
		} else {
			command = strings.Trim(inner, `"`)
		}
		break
	}
	for _, sep := range []string{" && ", " || ", " ; "} {
		if idx := strings.Index(command, sep); idx >= 0 {
			command = strings.TrimSpace(command[:idx])
			break
		}
	}
	return strings.Join(strings.Fields(command), " ")
}

func ExtractBashCommand(payload any) string {
	switch v := payload.(type) {
	case map[string]any:
		if s, ok := v["command"].(string); ok {
			return strings.TrimSpace(s)
		}
		if s, ok := v["cmd"].(string); ok {
			return strings.TrimSpace(s)
		}
	case string:
		return strings.TrimSpace(v)
	}
	return ""
}

func SummarizeOutput(output string) OutputSummary {
	trimmed := strings.TrimSpace(output)
	if trimmed == "" {
		return OutputSummary{}
	}
	lineCount := strings.Count(trimmed, "\n") + 1
	byteCount := len([]byte(trimmed))
	parts := []string{fmt.Sprintf("out=%s", FormatByteCount(byteCount))}
	if lineCount == 1 {
		parts = append(parts, "1 line")
	} else {
		parts = append(parts, fmt.Sprintf("%d lines", lineCount))
	}
	excerpt := ""
	if byteCount > 40 {
		for _, line := range strings.Split(trimmed, "\n") {
			line = strings.TrimSpace(line)
			if line == "" {
				continue
			}
			excerpt = BoundedText(RedactProgressOutput(line), 48)
			parts = append(parts, strconv.Quote(excerpt))
			break
		}
	}
	return OutputSummary{
		Summary: BoundedText(strings.Join(parts, " "), 96),
		Bytes:   byteCount,
		Lines:   lineCount,
		Excerpt: excerpt,
	}
}

func TokenThroughput(outputTokens int, durationMS int64) *float64 {
	if outputTokens <= 0 || durationMS <= 0 {
		return nil
	}
	v := float64(outputTokens) / (float64(durationMS) / 1000)
	return &v
}

func FormatByteCount(n int) string {
	switch {
	case n < 1024:
		return fmt.Sprintf("%dB", n)
	case n < 1024*1024:
		return fmt.Sprintf("%.1fKB", float64(n)/1024)
	default:
		return fmt.Sprintf("%.1fMB", float64(n)/(1024*1024))
	}
}

var sensitiveAssignmentPattern = regexp.MustCompile(`(?i)(api[_-]?key|secret|token|password|passwd|authorization|auth)\s*[:=]\s*[^,\s]+`)

func RedactProgressOutput(s string) string {
	if strings.TrimSpace(s) == "" {
		return ""
	}
	return sensitiveAssignmentPattern.ReplaceAllString(s, `$1=[redacted]`)
}

func summarizeSearchCommand(fields []string) ToolSummary {
	pattern := ""
	target := ""
	for _, field := range fields[1:] {
		if strings.HasPrefix(field, "-") {
			continue
		}
		if pattern == "" {
			pattern = strings.Trim(field, "'\"")
			continue
		}
		target = field
	}
	action := "search"
	if pattern != "" {
		action += " " + strconv.Quote(BoundedText(pattern, 32))
	}
	if target != "" {
		action += " in " + target
	}
	return ToolSummary{Action: action, Target: target}
}

func summarizeGitCommand(fields []string) ToolSummary {
	if len(fields) < 2 {
		return ToolSummary{Action: "git"}
	}
	switch fields[1] {
	case "add":
		target := strings.Join(fields[2:], " ")
		if target == "" {
			return ToolSummary{Action: "stage changes"}
		}
		return ToolSummary{Action: "stage changes", Target: target}
	case "commit":
		return ToolSummary{Action: "commit changes"}
	case "diff":
		return ToolSummary{Action: "inspect diff"}
	case "status":
		return ToolSummary{Action: "inspect git status"}
	case "log":
		return ToolSummary{Action: "inspect git log"}

