func TestWriteAndReplaySessionLog(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "svc-1.jsonl")
	logger := session.NewLogger(dir, "svc-1")
	logger.Emit(agentcore.EventSessionStart, session.SessionStartData{
