	return fromTranscriptProgressPayload(payload), true
}

func routeProgressData(decision RouteDecision) ServiceProgressData {
	input := transcript.RouteProgressDecision{
		Harness:  decision.Harness,
		Provider: decision.Provider,
		Model:    decision.Model,
		Power:    decision.Power,
	}
	if candidate := selectedRouteCandidate(decision); candidate != nil {
		input.Candidate = &transcript.RouteProgressCandidate{
			CostUSDPer1kTokens: candidate.CostUSDPer1kTokens,
			CostSource:         candidate.CostSource,
			Components: transcript.RouteProgressComponents{
				Power:    candidate.Components.Power,
				SpeedTPS: candidate.Components.SpeedTPS,
			},
		}
	}
	return fromTranscriptProgressPayload(transcript.RouteProgressData(input))
}

func selectedRouteCandidate(decision RouteDecision) *RouteCandidate {
	if len(decision.Candidates) == 0 {
		return nil
	}
	for i := range decision.Candidates {
		c := &decision.Candidates[i]
		if c.Harness == decision.Harness && c.Provider == decision.Provider && c.Model == decision.Model {
			return c
		}
	}
	for i := range decision.Candidates {
		c := &decision.Candidates[i]
		if c.Provider == decision.Provider && c.Model == decision.Model {
			return c
		}
	}
	if len(decision.Candidates) == 1 {
		return &decision.Candidates[0]
	}
	return nil
}

func progressTaskID(sessionID string, meta map[string]string) string {
	return transcript.TaskID(sessionID, meta)
}

func progressStatusLine(payload ServiceProgressData) string {
	return transcript.StatusLine(transcript.StatusLineInput{
		TaskID:      payload.TaskID,
		TurnIndex:   payload.Round,
		Message:     payload.Message,
		SinceLastMS: payload.SinceLastMS,
		Limit:       progressMessageLimit(payload),
	})
}

func compactProgressIdentity(taskID string, round int) string {
	return transcript.CompactIdentity(taskID, round)
}

func compactProgressTaskID(taskID string) string {
	return transcript.CompactTaskID(taskID)
}

func progressMessageLimit(payload ServiceProgressData) int {
	if payload.Phase == "tool" && payload.Command != "" {
		return progressExceptionalLineLimit
	}
	return progressLineLimit
}

func summarizeToolInput(toolName string, input json.RawMessage) string {
	if len(input) == 0 {
		return ""
	}
	if toolName == "bash" {
		var payload any
		if err := json.Unmarshal(input, &payload); err == nil {
			if command := extractBashCommand(payload); command != "" {
				return boundedProgressText(command, 120)
			}
		}
	}
	return boundedProgressText(summarizeJSONValue(input), 120)
}

// service is the concrete FizeauService implementation.
type service struct {
	opts     ServiceOptions
	registry *harnesses.Registry
	// harnessInstances holds the registered Harness implementation for
	// each known harness name. The refresh scheduler iterates over this
	// map, type-asserting each instance to the optional CONTRACT-004
	// sub-interfaces (QuotaHarness, AccountHarness). harnessByName is
	// the consultation seam.
	harnessInstances map[string]harnesses.Harness
	refreshScheduler *refreshScheduler
	hub              *sessionHub

	// lastDecisionMu guards lastDecisionCache.
	lastDecisionMu sync.RWMutex
	// lastDecisionCache maps route key → (decision, time). Populated by
	// ResolveRoute; read by RouteStatus.
	lastDecisionCache map[string]lastDecisionEntry

	routeHealth      *routehealth.Store
	routeLeases      *routehealth.LeaseStore
	routeUtilization *routehealth.UtilizationStore

	// catalog is the service-scope model-catalog cache. Populated lazily
	// on first use by routing + chat paths; shared across requests so the
	// same endpoint isn't probed per-dispatch during a drain. See
	// service_catalog_cache.go.
	catalog *catalogCache

	// routingQuality records routing-quality observations (ADR-006 §5).
	// Populated by Execute on every request and read by RouteStatus and
	// UsageReport.
	routingQuality *routingQualityStore

	// providerQuota is the per-provider quota state machine. Routing reads
	// the projected exhausted set on every Resolve so quota_exhausted
	// providers are excluded from candidate selection.
	providerQuota *ProviderQuotaStateStore

	// providerBurnRate observes per-provider token consumption against the
	// operator-configured daily_token_budget and pre-emptively transitions
	// providers into quota_exhausted when local burn-rate predicts the
	// budget will be exceeded before the next UTC daily reset.
	providerBurnRate *ProviderBurnRateTracker

	// providerProbe stores aliveness probe results for configured non-cloud
	// providers. Populated by startup and periodic background probes.
	providerProbe *routehealth.ProbeStore

	runtime serviceimpl.Runtime
}

const (
	defaultCatalogProbeTimeout  = 2 * time.Second
	defaultCatalogReloadTimeout = 30 * time.Second
)

func (o ServiceOptions) catalogProbeTimeout() time.Duration {
	if o.CatalogProbeTimeout > 0 {
		return o.CatalogProbeTimeout

// imported and ServiceConfig is nil, the service starts without provider config
// (ListProviders/HealthCheck will return errors until config is injected).
func New(opts ServiceOptions) (FizeauService, error) {
	if opts.ServiceConfig == nil && loadServiceConfig != nil && shouldAutoLoadServiceConfig(opts) {
		dir := ""
		if opts.ConfigPath != "" {
			dir = filepath.Dir(opts.ConfigPath)
		}
		sc, err := loadServiceConfig(dir)
		if err != nil {
			return nil, fmt.Errorf("agent.New: load config: %w", err)
		}
		opts.ServiceConfig = sc
	}
	svc := &service{
		opts:             opts,
		registry:         harnesses.NewRegistry(),
		harnessInstances: defaultHarnessInstances(),
		hub:              newSessionHub(),
		runtime:          serviceimpl.NewRuntime(serviceimpl.RuntimeDeps{}),
		catalog:          newCatalogCache(catalogCacheOptions{AsyncRefreshTimeout: opts.catalogRefreshTimeout()}),
		routeHealth:      routehealth.NewStore(),
		routeLeases:      routehealth.NewLeaseStore(),
		routeUtilization: routehealth.NewUtilizationStore(),
		routingQuality:   newRoutingQualityStore(),
		providerQuota:    NewProviderQuotaStateStore(),
		providerBurnRate: NewProviderBurnRateTracker(),
	}
	// Hydrate per-provider daily_token_budget from ServiceConfig so the
	// burn-rate tracker can predict exhaustion before the upstream quota
	// signal arrives.
	if opts.ServiceConfig != nil {
		for _, name := range opts.ServiceConfig.ProviderNames() {
			entry, ok := opts.ServiceConfig.Provider(name)
			if !ok {
				continue
			}
			if entry.DailyTokenBudget > 0 {
				svc.providerBurnRate.SetBudget(name, entry.DailyTokenBudget)
			}
		}
	}
	if opts.PersistRouteHealth == "" {
		opts.PersistRouteHealth = defaultRouteHealthPath(opts.ServiceConfig)
	}
	svc.opts = opts
	svc.providerProbe = routehealth.NewProbeStore()
	if opts.PersistRouteHealth != "" {
		_ = svc.providerProbe.Load(opts.PersistRouteHealth)
	}
	startupCtx := opts.QuotaRefreshContext
	if startupCtx == nil {
		startupCtx = context.Background()
	}
	svc.reapStaleHarnessSessions()
	svc.ensurePrimaryQuotaRefresh(startupCtx, quotaRefreshStartup)
	svc.startPrimaryQuotaRefreshWorker()
	svc.startQuotaRecoveryProbeLoop()
	svc.startupAlivenessProbe(context.Background())
	svc.startAlivenessProbeLoop()
	svc.refreshScheduler = newRefreshScheduler(svc.harnessByName, svc.registry.Names(), nil)

package fizeau

import (
	"context"
	"sync/atomic"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/serviceimpl"
)

type executeRouteResolver interface {
	resolveExecuteRoute(ServiceExecuteRequest) (*RouteDecision, error)
}

type executeSessionLogOpener interface {
	openSessionLog(ServiceExecuteRequest, RouteDecision, string) *serviceSessionLog
}

type executeEventFanout interface {
	openSession(string)
	broadcastEvent(string, ServiceEvent)
	closeSession(string, ServiceEvent)
	wrapExecuteWithHub(string, chan ServiceEvent, *overrideContext, map[string]string) chan ServiceEvent
}

type executeRunnerInvoker interface {
	dispatchExecuteRun(context.Context, executeRunContext)
}

type executeRunContext struct {
	req      ServiceExecuteRequest
	decision RouteDecision
	meta     map[string]string
	out      chan<- ServiceEvent
	seq      *atomic.Int64
	start    time.Time
	sl       *serviceSessionLog
	session  string
}

func (s *service) executeRouteResolver() executeRouteResolver {
	return s
}

func (s *service) executeSessionLogOpener() executeSessionLogOpener {
	return s
}

func (s *service) executeEventFanout() executeEventFanout {
	return s.hub
}

func (s *service) executeRunnerInvoker() executeRunnerInvoker {
	return s
}

func (s *service) dispatchExecuteRun(ctx context.Context, run executeRunContext) {
	decision := serviceimpl.ExecuteRunnerDecision{
		Harness:  run.decision.Harness,
		Provider: run.decision.Provider,
		Model:    run.decision.Model,
	}
	serviceimpl.DispatchExecuteRun(ctx, serviceimpl.ExecuteDispatchRequest{
		Decision: decision,
		Started:  run.start,
	}, serviceimpl.ExecuteDispatchCallbacks{
		RunNative: func(ctx context.Context) {
			s.runNative(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
		},
		RunSubprocess: func(ctx context.Context, runner harnesses.Harness) {
			s.runSubprocess(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session, runner)
		},
		RunVirtual: func(ctx context.Context) {
			s.runVirtual(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
		},
		RunScript: func(ctx context.Context) {
			s.runScript(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
		},
		IsHTTPProvider: func(harness string) bool {
			cfg, ok := s.registry.Get(harness)
			return ok && cfg.IsHTTPProvider
		},
		Finalize: func(final harnesses.FinalData) {
			finalizeAndEmit(run.out, run.seq, run.meta, run.req, run.sl, final)
		},
	})
}

//   - SessionLogDir per-request override
//
// Routing: under-specified requests (no Harness) are dispatched through
// internal/routing.Resolve via ResolveRoute. Callers can run with bare
// Policy/Model/Provider — the engine picks. NativeProvider must
// still be supplied for the native path until provider construction lands
// in a follow-up.
func (s *service) Execute(ctx context.Context, req ServiceExecuteRequest) (<-chan ServiceEvent, error) {
	// Boundary validation: reject unknown CachePolicy values before any
	// session state is opened or events are emitted. Beads C/D consume this
	// field; an unknown value is a caller programming error.
	if err := ValidateCachePolicy(req.CachePolicy); err != nil {
		return nil, err
	}
	if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
		return nil, err
	}
	if err := ValidateRole(req.Role); err != nil {
		return nil, err
	}
	if err := ValidateCorrelationID(req.CorrelationID); err != nil {
		return nil, err
	}

	// Generate a session ID and register it in the hub so TailSessionLog
	// callers can subscribe before or during execution.
	sessionID := generateSessionID()
	fanout := s.executeEventFanout()
	fanout.openSession(sessionID)

	outer := make(chan ServiceEvent, 64)

	// ADR-006 §3/§4: capture the override context (user pin + unconstrained
	// auto decision) before route resolution so we can fire the matching
	// override / rejected_override event regardless of which path the route
	// resolution takes.
	overrideCtx := s.buildOverrideContext(ctx, req)

	// ADR-006 §5: record this request into the routing-quality store so
	// auto_acceptance_rate / override_disagreement_rate / class_breakdown
	// reflect both overridden and non-overridden traffic. The recorded
	// override payload carries no outcome — outcome aggregation for live
	// requests is best-effort and lives in session logs once that
	// persistence path lands.
	s.recordRoutingQualityForRequest(overrideCtx)

	// Resolve the route.
	decision, err := s.executeRouteResolver().resolveExecuteRoute(req)
	if err != nil {
		// NoViableProviderForNow is a transient quota signal — DDx
		// callers pause their drain loop on RetryAfter and resume.
		// Surface it directly (not via the fatal-final channel) so the
		// typed error reaches errors.As without log scraping.
		var quotaErr *NoViableProviderForNow
		if errors.As(err, &quotaErr) {
			fanout.closeSession(sessionID, ServiceEvent{})
			return nil, err
		}
		if isExplicitPinError(err) {
			// Emit a rejected_override event (no outcome) when the pin
			// fails pre-dispatch. Surface the typed error wrapped with
			// the rejected_override payload so callers that errors.As
			// the typed pin error still get it; callers wanting the
			// telemetry can extract via AsRejectedOverride.
			pinErr := err
			if overrideCtx != nil {
				if rejectedEv, payload, ok := makeRejectedOverrideEvent(overrideCtx, sessionID, pinErr, req.Metadata); ok {
					fanout.broadcastEvent(sessionID, rejectedEv)
					// Persist the rejected_override to the session log so
					// UsageReport's windowed scan (which sources from
					// session logs, not the in-memory ring) sees this
					// rejection. The pin failed pre-dispatch, so no
					// runExecute will open a log for this session — open
					// one briefly here, write session.start + the rejected
					// payload, and close.
					s.persistRejectedOverride(req, sessionID, payload)
					pinErr = &ErrRejectedOverride{Inner: err, Event: payload}
				}
			}
			fanout.closeSession(sessionID, ServiceEvent{})
			return nil, pinErr
		}
		// Still return a channel that yields a single failed final event so
		// downstream consumers don't have to special-case the error path.
		// Also close the hub session so TailSessionLog subscribers unblock.
		go func() {
			emitFatalFinal(outer, req.Metadata, "failed", err.Error())
			// Drain outer to get the final event and forward to hub.
			// emitFatalFinal closes outer; read the single event from it.
		}()
		// We can't easily intercept emitFatalFinal here, so close the hub
		// session with an empty final immediately — callers on TailSessionLog
		// for a failed-route session get an empty close.
		go func() {
			// Wait briefly for emitFatalFinal to write.
			time.Sleep(10 * time.Millisecond)
			fanout.closeSession(sessionID, ServiceEvent{})
		}()
		return outer, nil
	}

	// Metadata seam: every event we emit echoes req.Metadata.
	meta := req.Metadata

	// Wrap the inner channel through the hub so every event is broadcast to
	// TailSessionLog subscribers. The fan-out goroutine owns outer's close
	// and is responsible for inserting the override event (if any) immediately
	// before the final event per ADR-006 §7.
	inner := fanout.wrapExecuteWithHub(sessionID, outer, overrideCtx, meta)

	// Emit start-of-execution routing_decision so consumers know the picked
	// chain before any real work fires. The actual chain (post-fallback) is
	// stamped onto the final event's RoutingActual field.
	go s.runExecute(ctx, req, *decision, meta, inner, sessionID, overrideCtx)
	return outer, nil
}

// resolveExecuteRoute reduces the request to a concrete RouteDecision.
// The request is dispatched through the routing engine
// (internal/routing.Resolve) when under-specified (Harness == ""), or when
// Harness is set but Model is empty and routing inputs (Policy or MinPower)
// are present (engine runs within the harness's eligible models). When Harness
// is set and Model is also set, the decision is accepted verbatim.
func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
	// If Harness is omitted, route through the engine. The engine defaults to
	// local-first and auto-selects from configured endpoints when no other
	// constraints are specified — an empty request is valid if providers exist.
	if req.Harness == "" {
		return s.resolveExecuteRouteWithEngine(req)
	}
	canonical := harnesses.ResolveHarnessAlias(req.Harness)

package fizeau

import (
	"path/filepath"
	"sync"
	"sync/atomic"
	"time"

	agentcore "github.com/easel/fizeau/internal/core"
	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/session"
)

// serviceSessionLog is the service-owned writer that persists the session
// lifecycle records (session.start + session.end) for one Execute call. It
// is constructed in runExecute after the route is resolved and torn down in
// a defer on the same goroutine. Sub-paths (runNative, runSubprocess, ...)
// emit the terminal event through finalizeAndEmit, which delegates here to
// keep the session log in sync with the public event stream.
type serviceSessionLog struct {
	logger    *session.Logger
	path      string
	sessionID string
	decision  RouteDecision
	override  *overrideContext
	endOnce   sync.Once
	endWrote  atomic.Bool
	closeOnce sync.Once

	progressMu     sync.Mutex
	lastProgressAt time.Time
}

// openSessionLog creates the session-log writer for req and emits the
// session.start record. A nil-or-empty req.SessionLogDir yields a no-op
// writer so callers don't need to branch on whether logging is enabled.
func (s *service) openSessionLog(req ServiceExecuteRequest, decision RouteDecision, sessionID string) *serviceSessionLog {
	if req.SessionLogDir == "" || sessionID == "" {
		return &serviceSessionLog{}
	}
	logger := session.NewLogger(req.SessionLogDir, sessionID)
	sl := &serviceSessionLog{
		logger:    logger,
		path:      filepath.Join(req.SessionLogDir, sessionID+".jsonl"),
		sessionID: sessionID,
		decision:  decision,
	}
	// CONTRACT-003: echo top-level Role + CorrelationID into the
	// session-log header (one line per session). Top-level wins over
	// any caller Metadata entry under the reserved keys.
	headerMeta := metaWithRoleAndCorrelation(req.Metadata, req.Role, req.CorrelationID)
	start := session.SessionStartData{
		Provider:               s.providerTypeLabel(decision.Provider),
		Model:                  decision.Model,
		SelectedProvider:       decision.Provider,
		SelectedEndpoint:       decision.Endpoint,
		SelectedServerInstance: decision.ServerInstance,
		SelectedRoute:          req.SelectedRoute,
		Sticky: session.RoutingStickyState{
			KeyPresent:     req.CorrelationID != "",
			Assignment:     decision.Sticky.Assignment,
			ServerInstance: decision.Sticky.ServerInstance,
			Reason:         decision.Sticky.Reason,
			Bonus:          decision.Sticky.Bonus,
		},
		Utilization: session.RoutingUtilizationState{
			Source:         decision.Utilization.Source,
			Freshness:      decision.Utilization.Freshness,
			ActiveRequests: decision.Utilization.ActiveRequests,
			QueuedRequests: decision.Utilization.QueuedRequests,
			MaxConcurrency: decision.Utilization.MaxConcurrency,
			CachePressure:  decision.Utilization.CachePressure,
			ObservedAt:     decision.Utilization.ObservedAt,
		},
		RequestedHarness: req.Harness,
		ResolvedHarness:  decision.Harness,
		HarnessSource:    harnessSource(req),
		RequestedModel:   req.Model,
		ResolvedModel:    decision.Model,
		Reasoning:        req.Reasoning,
		WorkDir:          req.WorkDir,
		MaxIterations:    req.MaxIterations,
		Prompt:           req.Prompt,
		SystemPrompt:     req.SystemPrompt,
		Metadata:         headerMeta,
	}
	logger.Emit(agentcore.EventSessionStart, start)
	if decision.Harness != "" || decision.Provider != "" || decision.Model != "" || len(decision.Candidates) > 0 || !decision.SnapshotCapturedAt.IsZero() {
		logger.Emit(agentcore.EventType(ServiceEventTypeRoutingDecision), serviceRoutingDecisionDataFromDecision(req, decision, sessionID))
	}
	return sl
}

// writeEnd records the terminal session.end event. It is idempotent: the
// first call wins. Callers should invoke this whenever a harnesses.FinalData
// is produced — finalizeAndEmit threads it together with the public-stream
// emit so the two views stay consistent.
func (sl *serviceSessionLog) writeEnd(req ServiceExecuteRequest, meta map[string]string, final harnesses.FinalData) {
	if sl == nil || sl.logger == nil {
		return
	}
	sl.endOnce.Do(func() {
		sl.endWrote.Store(true)
		end := session.SessionEndData{
			Status:           harnessStatusToCoreStatus(final.Status),
			ProcessOutcome:   processOutcomeForFinal(final.Status),
			Output:           final.FinalText,
			Tokens:           finalUsageToCoreTokens(final.Usage),
			DurationMs:       final.DurationMS,
			SelectedRoute:    req.SelectedRoute,
			SelectedEndpoint: sl.decision.Endpoint,
			Sticky: session.RoutingStickyState{
				KeyPresent:     req.CorrelationID != "",
				Assignment:     sl.decision.Sticky.Assignment,
				ServerInstance: sl.decision.Sticky.ServerInstance,
				Reason:         sl.decision.Sticky.Reason,
				Bonus:          sl.decision.Sticky.Bonus,
			},
			Utilization: session.RoutingUtilizationState{
				Source:         sl.decision.Utilization.Source,
				Freshness:      sl.decision.Utilization.Freshness,
				ActiveRequests: sl.decision.Utilization.ActiveRequests,
				QueuedRequests: sl.decision.Utilization.QueuedRequests,
				MaxConcurrency: sl.decision.Utilization.MaxConcurrency,
				CachePressure:  sl.decision.Utilization.CachePressure,
				ObservedAt:     sl.decision.Utilization.ObservedAt,
			},
			RequestedHarness: req.Harness,
			ResolvedHarness:  "",
			HarnessSource:    harnessSource(req),
			RequestedModel:   req.Model,
			Reasoning:        req.Reasoning,
			Metadata:         meta,
			Error:            final.Error,
		}
		if final.CostUSD > 0 {
			cost := final.CostUSD
			end.CostUSD = &cost
		}
		if req.CostCapUSD > 0 {
			cap := req.CostCapUSD
			end.CostCapUSD = &cap
		}
		if final.RoutingActual != nil {
			end.ResolvedHarness = final.RoutingActual.Harness
			end.Model = final.RoutingActual.Model
			end.SelectedProvider = final.RoutingActual.Provider
			if final.RoutingActual.ServerInstance != "" {
				end.SelectedServerInstance = final.RoutingActual.ServerInstance
			}
			end.ResolvedModel = final.RoutingActual.Model
			end.AttemptedProviders = append([]string(nil), final.RoutingActual.FallbackChainFired...)
			if len(end.AttemptedProviders) > 1 {
				end.FailoverCount = len(end.AttemptedProviders) - 1
			}
		}
		if final.Reasoning != nil {
			end.ResolvedReasoning = agentcore.Reasoning(final.Reasoning.ResolvedReasoning)
			end.ReasoningSource = final.Reasoning.Source
		}
		if end.SelectedServerInstance == "" {
			end.SelectedServerInstance = sl.decision.ServerInstance
		}
		sl.logger.Emit(agentcore.EventSessionEnd, end)
	})
}

// writeEvent persists a raw agent event to the session log. Used by the
// native loop callback to capture llm.request / llm.response / tool.call /
// compaction.* events so kept-sandbox bundles preserve a complete trace
// for benchmark reruns and post-mortem debugging. session.start and
// session.end are skipped because writeStart/writeEnd own those records and
// enrich them with service-side routing fields the loop does not see.
func (sl *serviceSessionLog) writeEvent(ev agentcore.Event) {
	if sl == nil || sl.logger == nil {
		return
	}
	switch ev.Type {
	case agentcore.EventSessionStart, agentcore.EventSessionEnd,
		agentcore.EventOverride, agentcore.EventRejectedOverride:
		return
	}
	sl.logger.Write(ev)
}

// writeOverrideEvent persists an override or rejected_override payload to
// the session log so windowed reporting (UsageReport, ADR-006 §5) can
// recompute routing-quality across restarts and beyond the in-memory
// ring's bounded retention. eventType is one of ServiceEventTypeOverride
// / ServiceEventTypeRejectedOverride.
func (sl *serviceSessionLog) writeOverrideEvent(eventType string, payload ServiceOverrideData) {
	if sl == nil || sl.logger == nil {
		return
	}
	payload.SessionID = sl.sessionID
	sl.logger.Emit(agentcore.EventType(eventType), payload)
}

// close flushes the underlying file. Safe to call multiple times.
func (sl *serviceSessionLog) close() {
	if sl == nil || sl.logger == nil {
		return
	}
	sl.closeOnce.Do(func() {
		_ = sl.logger.Close()
	})
}

// endWritten reports whether writeEnd has already recorded a terminal event.
func (sl *serviceSessionLog) endWritten() bool {
	if sl == nil {
		return false
	}
	return sl.endWrote.Load()
}

// persistRejectedOverride writes a session.start + rejected_override pair
// to a freshly-opened session log for sessionID. Used by Execute's
// pre-dispatch rejection branch, which never reaches runExecute and so
// never goes through the normal openSessionLog path. Without this,
// rejected_override events are invisible to UsageReport (which scans
// session logs over a --since window).
//
// The session.start is required by ScanRoutingQuality, which only counts
// log files that include one — and we want this rejection counted in
// TotalRequests so AutoAcceptanceRate reflects reality.
func (s *service) persistRejectedOverride(req ServiceExecuteRequest, sessionID string, payload ServiceOverrideData) {
	if req.SessionLogDir == "" || sessionID == "" {
		return
	}
	sl := s.openSessionLog(req, RouteDecision{}, sessionID)
	if sl == nil || sl.logger == nil {
		return
	}
	defer sl.close()
	sl.writeOverrideEvent(ServiceEventTypeRejectedOverride, payload)
}

// providerTypeLabel maps a configured provider name ("local") to its provider
// type ("lmstudio") when available. Returns the input unchanged if no
// ServiceConfig is attached or the name is not configured. Callers use this
// to populate session-log Provider fields, which historically carry the
// provider *type* rather than the configured name.
func (s *service) providerTypeLabel(name string) string {
