383		for _, known := range subprocessHarnessModelIDs(name, cfg) {
384			if model == known {
385				return true
386			}
387		}
388		switch name {
389		case "codex":
390			return strings.HasPrefix(model, "gpt-")
391		case "claude":
392			return strings.HasPrefix(model, "claude-")
393		case "pi":
394			// Pi can route to non-Gemini backends (lmstudio, omlx, etc.) when a
395			// provider is pinned. The pi CLI owns per-provider model validation
396			// in that case, so the agent-side gate trusts the provider pin and
397			// defers concrete model-ID checks to pi --list-models / pi itself.
398			return provider != ""
399		case "opencode":
400			// OpenCode can route to configured provider/model pairs when the
401			// provider is pinned; the generated opencode config and CLI own the
402			// concrete model validation in that case.
403			return provider != ""
404		default:
405			return len(cfg.Models) == 0
406		}
407	}
