409	func (s *service) validateEngineResolvedExecuteDecision(req ServiceExecuteRequest, decision *RouteDecision) error {
410		if decision == nil || strings.TrimSpace(req.Harness) == "" || strings.TrimSpace(req.Model) != "" {
411			return nil
412		}
413		canonical := harnesses.ResolveHarnessAlias(req.Harness)
414		if decision.Harness != "" && decision.Harness != canonical {
415			return &ErrUnsatisfiablePin{
416				Pin:    "harness=" + canonical,
417				Reason: "routing engine returned a different harness",
418			}
419		}
420		cfg, ok := s.registry.Get(canonical)
421		if !ok {
422			return fmt.Errorf("unknown harness %q", req.Harness)
423		}
424		normalizedModel := resolveSubprocessModelAlias(canonical, decision.Model)
425		if err := validateExplicitHarnessModel(canonical, cfg, normalizedModel, decision.Provider); err != nil {
426			return err
427		}
428		decision.Harness = canonical
429		decision.Model = normalizedModel
430		if decision.Endpoint == "" {
431			_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
432			decision.Endpoint = endpoint
433		}
434		return nil
435	}
