437	func validateExplicitHarnessReasoning(name string, cfg harnesses.HarnessConfig, value Reasoning) error {
438		if cfg.TestOnly {
439			return nil
440		}
441		if len(cfg.ReasoningLevels) == 0 && cfg.MaxReasoningTokens <= 0 {
442			return nil
443		}
444		policy, err := reasoning.ParseString(string(value))
445		if err != nil {
446			return fmt.Errorf("unsupported reasoning %q for harness %q: %w", value, name, err)
447		}
448		switch policy.Kind {
449		case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
450			return nil
451		case reasoning.KindTokens:
452			if cfg.MaxReasoningTokens <= 0 {
453				return fmt.Errorf("unsupported reasoning %q for harness %q; token budgets are not supported", value, name)
454			}
455			if policy.Tokens > cfg.MaxReasoningTokens {
456				return fmt.Errorf("unsupported reasoning %q for harness %q; max token budget is %d", value, name, cfg.MaxReasoningTokens)
457			}
458			return nil
459		case reasoning.KindNamed:
460			for _, supported := range cfg.ReasoningLevels {
461				if string(policy.Value) == supported {
462					return nil
463				}
464			}
465			return fmt.Errorf("unsupported reasoning %q for harness %q; supported reasoning: %s", value, name, strings.Join(cfg.ReasoningLevels, ", "))
466		default:
467			return fmt.Errorf("unsupported reasoning %q for harness %q", value, name)
468		}
469	}
