478	// runExecute is the per-Execute goroutine. It owns the channel close path
479	// and the final event emit. All termination paths funnel through emitFinal
480	// so the channel always sees a final event before close.
481	func (s *service) runExecute(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, sessionID string, overrideCtx *overrideContext) {
482		defer close(out)
483	
484		start := time.Now()
485		var seq atomic.Int64
486	
487		// Open the service-owned session log writer and guarantee a terminal
488		// session.end record plus a clean file close even on unexpected exits.
489		// CONTRACT-003 makes session-log lifecycle a service responsibility; the
490		// per-path finalizeAndEmit calls below feed writeEnd in lock-step with
491		// the public final event.
492		sl := s.executeSessionLogOpener().openSessionLog(req, decision, sessionID)
493		if overrideCtx != nil {
494			sl.override = overrideCtx
495		}
496		defer func() {
497			if !sl.endWritten() {
498				sl.writeEnd(req, meta, harnesses.FinalData{
499					Status:     "cancelled",
500					Error:      "session ended without final event",
501					DurationMS: time.Since(start).Milliseconds(),
502					RoutingActual: &harnesses.RoutingActual{
503						Harness:  decision.Harness,
504						Provider: decision.Provider,
505						Model:    decision.Model,
506					},
507				})
508			}
509			sl.close()
510		}()
511	
512		// Wall-clock cap.
513		runCtx := ctx
514		if req.Timeout > 0 {
515			var cancel context.CancelFunc
516			runCtx, cancel = context.WithTimeout(ctx, req.Timeout)
517			defer cancel()
518		}
519	
520		// Emit routing_decision start event. Include session_id so callers can

520		// Emit routing_decision start event. Include session_id so callers can
521		// extract it and pass to TailSessionLog. Per CONTRACT-003 the
522		// top-level Role + CorrelationID are echoed into routing_decision
523		// event Metadata (top-level wins over caller Metadata for these
524		// reserved keys).
525		routingMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
526		emitJSON(out, &seq, harnesses.EventTypeRoutingDecision, routingMeta, serviceRoutingDecisionDataFromDecision(req, decision, sessionID))
527		emitProgress(out, &seq, sl, sessionID, meta, routeProgressData(decision))
528	
529		s.executeRunnerInvoker().dispatchExecuteRun(runCtx, executeRunContext{
530			req:      req,
531			decision: decision,
532			meta:     meta,
533			out:      out,
534			seq:      &seq,
535			start:    start,
536			sl:       sl,
537			session:  sessionID,
538		})
539	}
