542		progress := newSubprocessProgressState(req)
543		emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
544		result := serviceimpl.RunVirtual(ctx, executeRunnerRequest(req, decision, meta, start))
545		final := result.Final
