590	// runNative drives the in-process agent loop (loop.go's Run). The provider
591	// is wrapped so per-HTTP timeouts fire independently of the request wall-clock
592	// cap.
593	func (s *service) runNative(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
594		progress := newNativeProgressState()
595		observeAgentEvent := func(ev agentcore.Event) {
596			sl.writeEvent(ev)
597			switch ev.Type {
598			case agentcore.EventLLMRequest:
599				var payload nativeLLMRequestPayload
600				if err := json.Unmarshal(ev.Data, &payload); err == nil {
601					emitProgress(out, seq, sl, sessionID, meta, progress.noteRequest(payload))
602				}
603			case agentcore.EventLLMResponse:
604				var payload nativeLLMResponsePayload
605				if err := json.Unmarshal(ev.Data, &payload); err == nil {
606					emitProgress(out, seq, sl, sessionID, meta, progress.noteResponse(payload))
607				}
608			case agentcore.EventToolCall:
609				var payload nativeToolCallPayload
610				_ = json.Unmarshal(ev.Data, &payload)
611				toolName := payload.Tool
612				input := payload.Input
613				if input == nil {
614					if rawIn, err := json.Marshal(map[string]any{"tool": toolName}); err == nil {
615						input = rawIn
616					}
617				}
618				callID := fmt.Sprintf("call-%d", ev.Seq)
619				_, completeProgress := progress.noteToolCall(callID, payload)
620				emitJSONRaw(out, seq, harnesses.EventTypeToolCall, meta, harnesses.ToolCallData{
621					ID:    callID,
622					Name:  toolName,
623					Input: input,
624				})
625				emitJSONRaw(out, seq, harnesses.EventTypeToolResult, meta, harnesses.ToolResultData{
626					ID:         callID,
627					Output:     payload.Output,
628					Error:      payload.Error,
629					DurationMS: payload.DurationMS,
630				})
631				emitProgress(out, seq, sl, sessionID, meta, completeProgress)
632			case agentcore.EventCompactionEnd:
633				var payload nativeCompactionPayload
634				_ = json.Unmarshal(ev.Data, &payload)
635				emitJSONRaw(out, seq, harnesses.EventTypeCompaction, meta, map[string]any{
636					"messages_before": payload.MessagesBefore,
637					"messages_after":  payload.MessagesAfter,
638					"tokens_freed":    payload.TokensBefore - payload.TokensAfter,
639				})
640				compactionProgress, contextProgress := progress.noteCompaction(payload)
641				emitProgress(out, seq, sl, sessionID, meta, compactionProgress)
642				emitProgress(out, seq, sl, sessionID, meta, contextProgress)
643			}
644		}
645	
646		var stallMaxReadOnlyIterations *int
647		if req.StallPolicy != nil {
648			stallMaxReadOnlyIterations = &req.StallPolicy.MaxReadOnlyToolIterations
649		}
650		serviceimpl.RunNative(ctx, serviceimpl.NativeRequest{
651			Prompt:                    req.Prompt,
652			SystemPrompt:              req.SystemPrompt,
653			Model:                     req.Model,
654			Provider:                  req.Provider,
655			Harness:                   req.Harness,
656			WorkDir:                   req.WorkDir,
657			Temperature:               req.Temperature,
658			TopP:                      req.TopP,
659			TopK:                      req.TopK,
660			MinP:                      req.MinP,
661			RepetitionPenalty:         req.RepetitionPenalty,
662			Seed:                      req.Seed,
663			SamplingSource:            req.SamplingSource,
664			Reasoning:                 effectiveReasoning(req.Reasoning),
665			NoStream:                  req.NoStream,
666			Permissions:               req.Permissions,
667			Tools:                     nativeToolsForRequest(req),
668			ToolPreset:                req.ToolPreset,
669			PlanningMode:              req.PlanningMode,
670			MaxIterations:             req.MaxIterations,
671			MaxTokens:                 req.MaxTokens,
672			ReasoningByteLimit:        req.ReasoningByteLimit,
673			ProviderTimeout:           req.ProviderTimeout,
674			Timeout:                   req.Timeout,
675			CachePolicy:               req.CachePolicy,
676			CostCapUSD:                req.CostCapUSD,
677			StallMaxReadOnlyIteration: stallMaxReadOnlyIterations,
678			Metadata:                  meta,
679			Decision:                  nativeDecision(decision),
680			Started:                   start,
681			SessionID:                 sessionID,
682		}, serviceimpl.NativeCallbacks{
683			ResolveProvider: func(nreq serviceimpl.NativeProviderRequest) serviceimpl.NativeProviderResolution {
684				resolved := s.resolveNativeProvider(ServiceExecuteRequest{
685					Provider: nreq.Provider,
686					Harness:  nreq.Harness,
687					Model:    nreq.Model,
688				})
689				return serviceimpl.NativeProviderResolution{
690					Provider: resolved.Provider,
691					Name:     resolved.Name,
692					Model:    resolved.Entry.Model,
693				}
694			},
695			ProviderNotConfiguredError: func(nreq serviceimpl.NativeProviderRequest, ndecision serviceimpl.NativeDecision) string {
696				return s.nativeProviderNotConfiguredError(ServiceExecuteRequest{
697					Provider: nreq.Provider,
698					Harness:  nreq.Harness,
699					Model:    nreq.Model,
700				}, routeDecision(ndecision))
701			},
702			Compactor: func(model string) agentcore.Compactor {
703				return newServiceCompactor(req, model)
704			},
705			ObserveAgentEvent: observeAgentEvent,
706			EmitEvent: func(t harnesses.EventType, payload any) {
707				emitJSONRaw(out, seq, t, meta, payload)
708			},
709			BeforeFinal: func(final harnesses.FinalData) {
710				if progressFinal := progress.noteFinal(final); progressFinal != nil {
711					emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
712				}
713			},
714			Finalize: func(final harnesses.FinalData) {
715				finalizeAndEmit(out, seq, meta, req, sl, final)
716			},
717			ToolWiringHook:          s.toolWiringHook(),
718			PromptAssertionHook:     s.promptAssertionHook(),
719			CompactionAssertionHook: s.compactionAssertionHook(),
