760	func newServiceCompactor(req ServiceExecuteRequest, model string) agentcore.Compactor {
761		cfg := compaction.DefaultConfig()
762		if req.CompactionContextWindow > 0 {
763			cfg.ContextWindow = req.CompactionContextWindow
764			if cfg.ReserveTokens >= cfg.ContextWindow {
765				cfg.ReserveTokens = 0
766			}
767			if cfg.KeepRecentTokens > cfg.ContextWindow {
768				cfg.KeepRecentTokens = cfg.ContextWindow / 2
769			}
770		}
771		if req.CompactionReserveTokens > 0 {
772			cfg.ReserveTokens = req.CompactionReserveTokens
773		}
774		if catalog, err := modelcatalog.Default(); err == nil && catalog != nil && model != "" && req.CompactionContextWindow <= 0 {
775			if contextWindow := catalog.ContextWindowForModel(model); contextWindow > 0 {
776				cfg.ContextWindow = contextWindow
777			}
778		}
779		return compaction.NewCompactor(cfg)
780	}
