805			SessionLogPath: sessionLogPath(sl),
806		}, runner, serviceimpl.SubprocessCallbacks{
807			BeforeExecute: func() {
808				emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
809			},
810			BeforeFinal: func(final harnesses.FinalData) {
811			},
812			ObserveEvent: func(ev harnesses.Event) harnesses.Event {
813				ev = progress.annotateToolResultDuration(ev)
814				if payload, ok := progress.noteEvent(ev); ok && ev.Type != harnesses.EventTypeProgress {
815					emitProgress(out, seq, sl, sessionID, meta, payload)
