821				}
822				return ev
823			},
824			EmitEvent: func(ev harnesses.Event) bool {
825				ev.Sequence = seq.Add(1) - 1
826				select {
827				case out <- ev:
828					return true
829				case <-ctx.Done():
830					return false
831				}
832			},
833			Finalize: func(final harnesses.FinalData) {
834				finalizeAndEmit(out, seq, meta, req, sl, final)
835			},
836			WriteEnd: func(finalMeta map[string]string, final harnesses.FinalData) {
837				sl.writeEnd(req, finalMeta, final)
838			},
839		})
