849	// emitFinal wraps a FinalData into a ServiceEvent and writes it to out.
850	// The channel close happens in the caller via defer; this only writes the
851	// terminator event.
852	func emitFinal(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, final harnesses.FinalData) {
853		raw, err := json.Marshal(final)
854		if err != nil {
855			raw = []byte(`{"status":"failed","error":"marshal final"}`)
856		}
857		ev := harnesses.Event{
858			Type:     harnesses.EventTypeFinal,
859			Sequence: seq.Add(1) - 1,
860			Time:     time.Now().UTC(),
861			Metadata: meta,
862			Data:     raw,
863		}
864		select {
865		case out <- ev:
866		case <-time.After(time.Second):
867		}
868	}
