870	// emitFatalFinal is used when Execute itself can't construct a route. It
871	// writes a single failed final event then closes the channel — used for
872	// the "no consumer goroutine" path so we still satisfy the channel
873	// contract.
874	func emitFatalFinal(out chan<- ServiceEvent, meta map[string]string, status, errMsg string) {
875		defer close(out)
876		final := harnesses.FinalData{Status: status, Error: errMsg}
877		raw, _ := json.Marshal(final)
878		ev := harnesses.Event{
879			Type:     harnesses.EventTypeFinal,
880			Sequence: 0,
881			Time:     time.Now().UTC(),
882			Metadata: meta,
883			Data:     raw,
884		}
885		select {
886		case out <- ev:
887		case <-time.After(time.Second):
888		}
889	}
